command.text:
        &CommandWhenBeforeDelete;

if exists(select * from hrrmlichctuv where ma_dot = @ma_dot)
  begin
    select @$deleteConflict as message
    return
  end

script.text:

function active$hrRMTestInterviewSchedule(f) {
	f.add_onResponseComplete(on$hrRMTestInterviewSchedule$ResponseComplete);
	f.add_commandEvent(on$hrRMTestInterviewSchedule$ExecuteCommand);
	if (f._action != 'View') f.setReadOnlyFields('ngay_tu, ngay_den');
}
function close$hrRMTestInterviewSchedule(f) {
	try {f.remove_onResponseComplete(on$hrRMTestInterviewSchedule$ResponseComplete)} catch (ex) {}
	try {f.remove_commandEvent(on$hrRMTestInterviewSchedule$ExecuteCommand);} catch (ex) {}
}
function on$hrRMTestInterviewSchedule$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('hrrmlichct')._controlBehavior;
  switch (action) {
    case 'Gather':
		  g.setContinuance('stt_rec0');
      g.setSequenceNumber('line_nbr');
      break;
    default:
      break;
  }
}
function on$hrRMTestInterviewSchedule$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
		case 'RecruitmentPeriod':
			if (result[0].Value != '') f.setItemValues('ma_dvcs, ngay_tu, ngay_den', [result[0].Value, result[1].Value, result[2].Value]);
      break;
    default:
      break;
  }
}

function onChange$RecruitmentPeriod(o) {
  o.parentForm.request('RecruitmentPeriod', 'RecruitmentPeriod', ['ma_dot'], o);
  var g = o.parentForm.getItem("hrrmlichct")._controlBehavior;
  set$Voucher$Site$EmptyRecruitmentPeriod(g, 'ma_vtr');
  set$Voucher$Site$EmptyRecruitmentPeriod(g, 'ten_vtr%l');
}

function set$Voucher$Site$EmptyRecruitmentPeriod(g, c) {
  var o = g._activeCell, l = g._getColumnOrder(c);
  if (l == g._activeColumn) {
    if (o._controlBehavior) {
      var fields = g._fields, field = g._fields[l - 1], r = o.row, id = g.get_id();
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($func.completionFilter(o, fields, field.ItemKeyFilter, r, id));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($func.completionFilter(o, fields, field.ItemCheckFilter, r, id));
    }
  }
  for (var i = 0; i < g._rowCount; i++) {
    o = g._getItem(i + 1, l);
    if (!o.row) o.value = '';
      else {
        o.row = i + 1;
        g.setItemGridBehavior(o, [[c, '', '']]);
      }
  }
}
